script:
frappe.ui.form.on('Sales Invoice', {
    // Trigger when the form is loaded
    onload: function(frm) {
        // Set date field to today
        frm.set_value('date', frappe.datetime.get_today());

        // Set time field to now
        frm.set_value('time', frappe.datetime.get_time());
    },
    
    price_list(frm){

        if(!frm.doc.price_list)
            return
            
        let items = frm.doc.items.map(d => d.item);

        frappe.call({
            method: "get_items_prices",
            doc: frm.doc,
            args: {
                items: items,
                price_list: frm.doc.price_list
            },
            callback: function(r) {

                if (r.message) {

                    let prices = r.message;

                    frm.doc.items.forEach(row => {

                        let price = prices[row.item];

                        if (price !== undefined) {
                            frappe.model.set_value(
                                row.doctype,
                                row.name,
                                "rate",
                                price
                            );
                        }
                    });

                    frm.refresh_field("items");
                }
            }
        });
    },
    
    source_warehouse(frm){
        frm.doc.items.forEach(item =>{
            item.source_warehouse = frm.doc.source_warehouse
        })
    },
    
    total(frm) {
        

        let grand_total = frm.doc.total || 0;

        // Recalculate all taxes
        (frm.doc.tax || []).forEach(row => {

            let tax_amount = (row.tax_rate || 0) * grand_total / 100;
            let tax_result = grand_total + tax_amount;

            frappe.model.set_value(
                row.doctype,
                row.name,
                "amount",
                tax_amount
            );

            frappe.model.set_value(
                row.doctype,
                row.name,
                "result",
                tax_result
            );
        });
        
        
        calculate_net_total(frm)
        
    },
    
    net_total(frm){
        calculate_grand_total(frm)
    }
});





frappe.ui.form.on('Sales Invoice Item', {
    
    items_add(frm, cdt, cdn){
        //task 1 ==> recalculate the total qty
        calculate_items_total_qty(frm)
        //task 2 ==> add the default warehouses to the new record
        let row = locals[cdt][cdn]
        frappe.model.set_value(cdt,cdn,"source_warehouse",frm.doc.source_warehouse)
        //task 3 : recalculate table total amount
        calculate_items_total_amount(frm)
    },
    
    items_remove(frm, cdt, cdn){
        //task 1 ==> recalculate the total qty
        calculate_items_total_qty(frm)
        //task 2 : recalculate table total amount
        calculate_items_total_amount(frm)
    },
    item(frm, cdt, cdn) {

        let row = locals[cdt][cdn];

        if (!row.item || !frm.doc.price_list) return;

        frappe.call({
            method: "get_items_prices",
            doc: frm.doc,
            args: {
                items: [row.item],
                price_list: frm.doc.price_list
            },
            callback: function(r) {

                if (r.message) {

                    let price = r.message[row.item];

                    if (price !== undefined) {
                        frappe.model.set_value(
                            cdt,
                            cdn,
                            "rate",
                            price
                        );
                    }
                }
            }
        });
    },
    qty(frm , cdt , cdn){
        // task 1 ==> recalculate the amount
        calculate_items_total_amount(frm)
        
        //task 2 ==> recalculate the total qty
        calculate_items_total_qty(frm)
    },
    rate(frm , cdt , cdn){
        // task 1 ==> recalculate the amount
        let row = locals[cdt][cdn]
        let amount = row.qty * row.rate
        frappe.model.set_value(cdt,cdn,"amount",amount)
    },
    amount(frm , cdt , cdn){
        //task 1 : recalculate table total amount
        calculate_items_total_amount(frm)

    }
    
});


frappe.ui.form.on('Sales Invoice Tax', {

    tax(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        
        if(!row.tax){
            frappe.model.set_value(cdt,cdn,"tax_rate", 0 )
            frappe.model.set_value(cdt,cdn,"amount",  0)
            frappe.model.set_value(cdt,cdn,"result", 0)
        }
        
        
        

        if (!row.tax) return;

        frappe.call({
            method: "frappe.client.get",
            args: {
                doctype: "Tax",
                name: row.tax
            },
            callback: function(r) {
                
                let tax_rate   = r.message.tax_rate
                let tax_amount = r.message.tax_rate * frm.doc.total / 100
                let tax_result = tax_amount + frm.doc.total
                if (r.message) {
                    frappe.model.set_value(cdt,cdn,"tax_rate", tax_rate )
                    frappe.model.set_value(cdt,cdn,"amount",  tax_amount)
                    frappe.model.set_value(cdt,cdn,"result", tax_result)
                }
            }
        });
    },
    
    amount(frm , cdt , cdn){
        //task 1 ====> recalcul net total
        calculate_net_total(frm)
    },
    
    tax_remove(frm , cdt , cdn){
        calculate_net_total(frm)
    }
    


});


frappe.ui.form.on('Sales Invoice Discount', {

    discount(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        
        if(!row.discount){
            frappe.model.set_value(cdt,cdn,"discount_rate", 0 )
            frappe.model.set_value(cdt,cdn,"amount",  0)
            frappe.model.set_value(cdt,cdn,"result", 0)
        }
        

        if (!row.discount) return;

        frappe.call({
            method: "frappe.client.get",
            args: {
                doctype: "Discount",
                name: row.discount
            },
            callback: function(r) {
                
                let discount_rate   = r.message.discount_rate
                let discount_amount = r.message.discount_rate * frm.doc.net_total / 100
                let discount_result = discount_amount + frm.doc.net_total
                if (r.message) {
                    frappe.model.set_value(cdt,cdn,"discount_rate", discount_rate )
                    frappe.model.set_value(cdt,cdn,"amount",  discount_amount)
                    frappe.model.set_value(cdt,cdn,"result", discount_result)
                }
            }
        });
    },
    
    amount(frm, cdt, cdn){
        calculate_grand_total(frm)
    }

});







//helper functions
function calculate_items_total_amount(frm) {

    let total_amount = 0;

    (frm.doc.items || []).forEach(item => {
        let qty = item.qty || 0;
        let rate = item.rate || 0;
        total_amount += qty * rate;
    });

    frm.set_value("total", total_amount);
}

function calculate_items_total_qty(frm) {

    let total_qty = 0;

    (frm.doc.items || []).forEach(item => {
        let qty = item.qty || 0;
        total_qty += qty;
    });

    frm.set_value("total_qty", total_qty);
}

function calculate_grand_total(frm){
    let net_total = frm.doc.net_total;
    let total_discount = 0;
    frm.doc.discount.forEach(d =>{
        total_discount -= d.amount;
    })
    
    let result = net_total + total_discount;
    
    frm.set_value("grand_total", result);
}



function calculate_net_total(frm){
    
    let total = frm.doc.total;
    let total_tax = 0;
    frm.doc.tax.forEach(t =>{
        total_tax += t.amount;
    })
    
    let result = total + total_tax;
    
    frm.set_value("net_total", result);
}
